BoxItemConfig = {}
BoxItemConfig.Items = {}
BoxItemConfig.Pools = {}

function BoxItemConfig:init(config)
    for id, boxItem in pairs(config) do
        local item = {}
        item.id = boxItem.id
        item.itemId = tonumber(boxItem.itemId)
        item.poolId = boxItem.poolId
        item.min = tonumber(boxItem.min)
        item.max = tonumber(boxItem.max)
        item.weight = tonumber(boxItem.weight)
        self.Items[item.id] = item
        if self.Pools[item.poolId] == nil then
            self.Pools[item.poolId] = {}
        end
        table.insert(self.Pools[item.poolId], item)
    end
end

function BoxItemConfig:getPoolById(id)
    local pool = self.Pools[tostring(id)]
    if pool == nil then
        return nil
    end
    return pool
end

return BoxItemConfig